mapper.select:
select a.id, 'AUC-' || lpad(a.id::text, 3, '0') as auction_code, w.title as artwork_title, sm.nickname as artist_nickname, a.winner_id, wm.nickname as winner_nickname, a.starting_price as start_price, a.final_price as winning_price, a.bid_count, to_char(a.closing_at, 'YYYY.MM.DD') as end_at, 'FINISHED' as status from tbl_auction a join tbl_work w on a.work_id = w.id join tbl_member sm on a.seller_id = sm.id left join tbl_member wm on a.winner_id = wm.id where a.status in ('CLOSED', 'SOLD')
and ( w.title ilike '%' || #{keyword} || '%' or sm.nickname ilike '%' || #{keyword} || '%' or ('AUC-' || lpad(a.id::text, 3, '0')) ilike '%' || #{keyword} || '%' )
order by a.id desc limit #{size} offset #{offset}
